using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr progressDialog = ui->createProgressDialog();
    if (!progressDialog)
        return false;

    // Set styles of progress dialog.
    progressDialog->cancelButtonText("Cancel");
    progressDialog->isBackgroundTranslucent(false);
    progressDialog->isCancelButtonShown(true);

    // Show dialog
    progressDialog->show("Progress Dialog", "Percentage: %p, Current Value: %v, Total steps: %m", 0, 50, 1);

    // Draw sketches and update status.
    Ptr design = app->activeProduct();
    if (!design)
        return false;

    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;

    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;

    Ptr circles = curves->sketchCircles();
    if (!circles)
        return false;

    Ptr centerPt = Point3D::create(0, 0, 0);
    if (!centerPt)
        return centerPt;
    for (int i = 0; i wasCancelled())
            break;
        circles->addByCenterRadius(centerPt, i + 1);

        // Update progress value of progress dialog
        progressDialog->progressValue(i + 1);
    }

    // Hide the progress dialog at the end.
    progressDialog->hide();

    return true;
}
